pub async fn quiesce(db: &Database) -> Result<()> {
    tracing::info!("QTR: entering Quiesce phase");
    db.checkpoint_wal()
        .context("failed to checkpoint WAL during quiesce")?;
    db.end_all_sessions()
        .context("failed to end sessions during quiesce")?;
    tracing::info!("QTR: quiesce complete — database is consistent");
    Ok(())
}

pub async fn transfer(source_path: &Path, dest_path: &Path) -> Result<blake3::Hash> {
    tracing::info!(
        "QTR: entering Transfer phase — {} → {}",
        source_path.display(),
        dest_path.display()
    );

    let source_data =
        std::fs::read(source_path).context("failed to read source file for transfer")?;
    let hash = blake3::hash(&source_data);

    if let Some(parent) = dest_path.parent() {
        std::fs::create_dir_all(parent)
            .context("failed to create destination directory")?;
    }

    std::fs::write(dest_path, &source_data)
        .context("failed to write destination file during transfer")?;

    tracing::info!("QTR: transfer complete — hash: {}", hash.to_hex());
    Ok(hash)
}

pub async fn resume(db: &Database, nail_path: &Path) -> Result<ShellProfile> {
    tracing::info!("QTR: entering Resume phase");

    if !nail_path.exists() {
        anyhow::bail!("nail file does not exist: {}", nail_path.display());
    }

    let profile = ShellProfile::probe().context("failed to probe new shell during resume")?;

    let _shell_id = profile
        .save_to_db(db.conn())
        .context("failed to save new shell profile")?;

    tracing::info!("QTR: resume complete — new shell: {}", profile.hostname);
    Ok(profile)
}

pub fn unpack(nail_path: &Path, target_dir: &Path) -> Result<NailManifest> {
    tracing::info!(
        "NailUnpack: starting unpack — {} → {}",
        nail_path.display(),
        target_dir.display()
    );

    let compressed =
        std::fs::read(nail_path).context("failed to read nail archive")?;
    let tar_data = zstd::bulk::decompress(&compressed, 64 * 1024 * 1024)
        .context("failed to decompress nail archive")?;

    std::fs::create_dir_all(target_dir)
        .context("failed to create target directory")?;

    let mut archive = tar::Archive::new(std::io::Cursor::new(&tar_data));
    archive
        .unpack(target_dir)
        .context("failed to extract tar archive")?;

    let manifest_path = target_dir.join("manifest.json");
    let manifest_data =
        std::fs::read_to_string(&manifest_path).context("failed to read manifest.json")?;
    let manifest: NailManifest =
        serde_json::from_str(&manifest_data).context("failed to parse manifest.json")?;

    // Verify database checksum
    let db_path = target_dir.join("reflexes.db");
    if db_path.exists() {
        let db_data = std::fs::read(&db_path).context("failed to read reflexes.db")?;
        let db_checksum = blake3::hash(&db_data).to_hex().to_string();
        if db_checksum != manifest.checksums.reflexes_db {
            anyhow::bail!(
                "database checksum mismatch: expected {}, got {}",
                manifest.checksums.reflexes_db,
                db_checksum
            );
        }
    }

    // Verify config checksum
    let config_path = target_dir.join("config.toml");
    if config_path.exists() {
        let config_data =
            std::fs::read(&config_path).context("failed to read config.toml")?;
        let config_checksum = blake3::hash(&config_data).to_hex().to_string();
        if config_checksum != manifest.checksums.config_toml {
            anyhow::bail!(
                "config checksum mismatch: expected {}, got {}",
                manifest.checksums.config_toml,
                config_checksum
            );
        }
    }

    // Validate the SQLite schema
    if db_path.exists() {
        validate_db_schema(&db_path)?;
    }

    tracing::info!(
        "NailUnpack: unpack complete — {} reflexes",
        manifest.reflex_count
    );

    Ok(manifest)
}

fn validate_db_schema(db_path: &Path) -> Result<()> {
    let conn = rusqlite::Connection::open(db_path)
        .context("failed to open database for schema validation")?;

    let tables: Vec<String> = conn
        .prepare("SELECT name FROM sqlite_master WHERE type='table' ORDER BY name")
        .and_then(|mut stmt| {
            stmt.query_map([], |row| row.get(0))
                .map(|rows| rows.filter_map(|r| r.ok()).collect())
        })
        .context("failed to query sqlite_master")?;

    let required = ["reflexes", "sessions", "shells"];
    for table in &required {
        if !tables.iter().any(|t| t == *table) {
            anyhow::bail!("missing required table: {}", table);
        }
    }

    tracing::info!("database schema validation passed");
    Ok(())
}

pub fn fingerprint() -> FingerprintResult<ShellFingerprint> {
    info!("Collecting hardware fingerprint");

    let mut sys = System::new_all();
    sys.refresh_all();

    let hostname = System::host_name().unwrap_or_else(|| "unknown".to_string());
    let os = System::name().unwrap_or_else(|| "unknown".to_string());
    let os_version = System::os_version().unwrap_or_else(|| "unknown".to_string());
    let cpu_count = sys.cpus().len();
    let ram_mb = sys.total_memory() / 1024 / 1024;

    // GPU detection — try to find GPU info
    let gpu = detect_gpu();

    // MAC address hash for network identity
    let mac_hash = compute_mac_hash();

    let fp = ShellFingerprint {
        hostname,
        os,
        os_version,
        cpu_count,
        ram_mb,
        gpu,
        mac_hash,
    };

    info!(fingerprint = %fp, "Hardware fingerprint collected");
    Ok(fp)
}

pub fn fingerprint_hash(fp: &ShellFingerprint) -> String {
    let canonical = format!(
        "{}|{}|{}|{}|{}|{}|{}",
        fp.hostname,
        fp.os,
        fp.os_version,
        fp.cpu_count,
        fp.ram_mb,
        fp.gpu,
        fp.mac_hash
    );

    blake3::hash(canonical.as_bytes()).to_hex().to_string()
}

pub fn compatibility_score(a: &ShellFingerprint, b: &ShellFingerprint) -> f32 {
    let mut score: f32 = 0.0;

    // OS match: critical — different OS families are problematic
    if a.os == b.os {
        score += 0.35;
        // OS version match: bonus
        if a.os_version == b.os_version {
            score += 0.10;
        } else {
            // Partial version match
            score += 0.05;
        }
    } else {
        // Completely different OS — major incompatibility
        // But still allow some score for cross-OS migration
        score += 0.05;
    }

    // CPU count similarity: more CPUs = more parallel capacity
    let cpu_ratio = if a.cpu_count > 0 && b.cpu_count > 0 {
        let min_cpu = a.cpu_count.min(b.cpu_count) as f32;
        let max_cpu = a.cpu_count.max(b.cpu_count) as f32;
        min_cpu / max_cpu
    } else {
        0.5 // Unknown
    };
    score += cpu_ratio * 0.15;

    // RAM similarity: affects context window and model loading
    let ram_ratio = if a.ram_mb > 0 && b.ram_mb > 0 {
        let min_ram = a.ram_mb.min(b.ram_mb) as f32;
        let max_ram = a.ram_mb.max(b.ram_mb) as f32;
        min_ram / max_ram
    } else {
        0.5
    };
    score += ram_ratio * 0.20;

    // GPU presence: both have GPU or both don't
    let gpu_match = (a.gpu != "none" && b.gpu != "none") || (a.gpu == "none" && b.gpu == "none");
    score += if gpu_match { 0.10 } else { 0.0 };

    // Hostname match: minor factor (same machine rebooted)
    if a.hostname == b.hostname {
        score += 0.05;
    }

    // MAC hash match: strong indicator of same physical machine
    if a.mac_hash == b.mac_hash && !a.mac_hash.is_empty() {
        score += 0.05;
    }

    score.min(1.0)
}

fn detect_gpu() -> String {
    // Try lspci first (Linux)
    if let Ok(output) = std::process::Command::new("lspci")
        .output()
    {
        let stdout = String::from_utf8_lossy(&output.stdout);
        for line in stdout.lines() {
            let line_lower = line.to_lowercase();
            if line_lower.contains("vga") || line_lower.contains("3d") || line_lower.contains("display") {
                // Extract GPU name
                if let Some(colon_pos) = line.find(':') {
                    let gpu_name = line[colon_pos + 1..].trim();
                    if !gpu_name.is_empty() {
                        return gpu_name.to_string();
                    }
                }
            }
        }
    }

    // Try nvidia-smi
    if let Ok(output) = std::process::Command::new("nvidia-smi")
        .args(["--query-gpu=name", "--format=csv,noheader"])
        .output()
    {
        if output.status.success() {
            let name = String::from_utf8_lossy(&output.stdout).trim().to_string();
            if !name.is_empty() {
                return name;
            }
        }
    }

    "none".to_string()
}

fn compute_mac_hash() -> String {
    let mut mac_info = String::new();

    // Try reading from /sys/class/net (Linux)
    if let Ok(entries) = std::fs::read_dir("/sys/class/net") {
        for entry in entries.flatten() {
            let name = entry.file_name().to_string_lossy().to_string();
            let addr_path = format!("/sys/class/net/{}/address", name);
            if let Ok(addr) = std::fs::read_to_string(&addr_path) {
                let addr = addr.trim().to_string();
                // Skip loopback
                if addr != "00:00:00:00:00:00" {
                    mac_info.push_str(&addr);
                }
            }
        }
    }

    if mac_info.is_empty() {
        return String::new();
    }

    blake3::hash(mac_info.as_bytes()).to_hex()[..16].to_string()
}

fn test_fingerprint() {
    let fp = fingerprint().unwrap();
    assert!(!fp.hostname.is_empty());
    assert!(!fp.os.is_empty());
    assert!(fp.cpu_count > 0);
    assert!(fp.ram_mb > 0);
}

fn test_fingerprint_hash_deterministic() {
    let fp = fingerprint().unwrap();
    let hash1 = fingerprint_hash(&fp);
    let hash2 = fingerprint_hash(&fp);
    assert_eq!(hash1, hash2);
    assert_eq!(hash1.len(), 64); // BLAKE3 hex length
}

