pub fn permissive() -> Self {
    Self {
        allow_network: true,
        read_only_paths: vec![],
        read_write_paths: vec!["/".into()],
        executable_whitelist: vec![],
        blocked_patterns: vec![
            "rm -rf /".into(),
            "rm -rf /*".into(),
            ":(){ :|:& };:".into(),
        ],
    }
}

pub fn is_blocked(&self, command: &str) -> bool {
    self.blocked_patterns
        .iter()
        .any(|p| command.contains(p.as_str()))
}

pub fn check_executable(&self, binary: &str) -> Result<()> {
    if self.executable_whitelist.is_empty() {
        return Ok(());
    }
    if self.executable_whitelist.iter().any(|w| binary == w.as_str()) {
        Ok(())
    } else {
        anyhow::bail!("binary '{}' is not in the executable whitelist", binary)
    }
}

pub fn execute(config: &SandboxConfig, command: &str, args: &[&str]) -> Result<ExecutionResult> {
    // Check blocked patterns first — no execution at all.
    let full_cmd = format!("{} {}", command, args.join(" "));
    if config.is_blocked(&full_cmd) {
        anyhow::bail!("command matches a blocked pattern: {}", full_cmd);
    }

    // Check executable whitelist.
    config.check_executable(command)?;

    let start = Instant::now();

    let result = if which_bwrap() {
        Self::execute_bwrap(config, command, args)
    } else {
        // SECURITY: Fail closed — refuse to execute without sandbox.
        // Do NOT fall back to unsandboxed execution.
        tracing::error!("bwrap not found — refusing to execute without sandbox. Install bubblewrap (bwrap).");
        anyhow::bail!(
            "FATAL: bwrap not found — refusing to execute without sandbox. \
             Install bubblewrap (bwrap) to enable sandboxed execution."
        )
    };

    let duration_ms = start.elapsed().as_millis() as u64;
    match result {
        Ok(mut r) => {
            r.duration_ms = duration_ms;
            Ok(r)
        }
        Err(e) => Err(e),
    }
}

fn execute_bwrap(config: &SandboxConfig, command: &str, args: &[&str]) -> Result<ExecutionResult> {
    let mut bwrap_args: Vec<String> = Vec::new();

    // Mount /usr, /lib, etc. read-only.
    for path in &config.read_only_paths {
        bwrap_args.push("--ro-bind".into());
        bwrap_args.push(path.clone());
        bwrap_args.push(path.clone());
    }

    // Mount read-write paths.
    for path in &config.read_write_paths {
        bwrap_args.push("--bind".into());
        bwrap_args.push(path.clone());
        bwrap_args.push(path.clone());
    }

    // Bind /proc (needed for basic operation).
    bwrap_args.push("--proc".into());
    bwrap_args.push("/proc".into());

    // Bind /dev (minimal).
    bwrap_args.push("--dev".into());
    bwrap_args.push("/dev".into());

    // Network policy.
    if !config.allow_network {
        bwrap_args.push("--unshare-net".into());
    }

    // The actual command to run inside the sandbox.
    bwrap_args.push("--".into());
    bwrap_args.push(command.into());
    for arg in args {
        bwrap_args.push((*arg).into());
    }

    let output = std::process::Command::new("bwrap")
        .args(&bwrap_args)
        .output()
        .with_context(|| format!("failed to execute bwrap with command: {}", command))?;

    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
    let exit_code = output.status.code().unwrap_or(-1);

    // Truncate stdout to 4 KiB for logging.
    let stdout_snippet = if stdout.len() > 4096 {
        stdout[..4096].to_string()
    } else {
        stdout
    };

    Ok(ExecutionResult {
        exit_code,
        stdout: stdout_snippet,
        stderr,
        duration_ms: 0, // filled in by caller
    })
}

fn execute_raw(command: &str, args: &[&str]) -> Result<ExecutionResult> {
    let output = std::process::Command::new(command)
        .args(args)
        .output()
        .with_context(|| format!("failed to execute command: {}", command))?;

    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
    let exit_code = output.status.code().unwrap_or(-1);

    let stdout_snippet = if stdout.len() > 4096 {
        stdout[..4096].to_string()
    } else {
        stdout
    };

    Ok(ExecutionResult {
        exit_code,
        stdout: stdout_snippet,
        stderr,
        duration_ms: 0,
    })
}

pub fn with_patterns(patterns: Vec<String>) -> Self {
    Self {
        blocked_patterns: patterns,
    }
}

pub fn check(&self, command: &str, manifest: &CapabilityManifest) -> VetoVerdict {
    // 1. Check blocked patterns.
    for pattern in &self.blocked_patterns {
        if command.contains(pattern.as_str()) {
            return VetoVerdict {
                allowed: false,
                reason: Some(format!("command matches blocked pattern: {}", pattern)),
                confidence: 1.0,
            };
        }
    }

    // 2. Check capability manifest.
    if let Some(verdict) = self.check_manifest(command, manifest) {
        return verdict;
    }

    // 3. If no manifest permissions at all, treat as novel.
    if manifest.permissions.is_empty() {
        return VetoVerdict {
            allowed: true,
            reason: Some("no capability manifest — treating as novel command".into()),
            confidence: 0.5,
        };
    }

    // 4. All checks passed.
    VetoVerdict {
        allowed: true,
        reason: None,
        confidence: 1.0,
    }
}

fn check_manifest(&self, command: &str, manifest: &CapabilityManifest) -> Option<VetoVerdict> {
    let parts: Vec<&str> = command.split_whitespace().collect();
    let binary = parts.first()?;

    if !manifest.has_execute(binary) && !manifest.permissions.is_empty() {
        let has_any_execute = manifest
            .permissions
            .iter()
            .any(|p| matches!(p, crate::capability::Permission::Execute { .. }));
        if has_any_execute {
            return Some(VetoVerdict {
                allowed: false,
                reason: Some(format!(
                    "binary '{}' is not in the execute permissions of manifest",
                    binary
                )),
                confidence: 1.0,
            });
        }
    }

    let uses_network = command.contains("curl")
        || command.contains("wget")
        || command.contains("nc ")
        || command.contains("ssh ");
    if uses_network && !manifest.allows_network() && !manifest.permissions.is_empty() {
        return Some(VetoVerdict {
            allowed: false,
            reason: Some("command appears to use network but manifest has no network permission".into()),
            confidence: 0.8,
        });
    }

    None
}

fn default() -> Self {
    Self::new()
}

pub fn mint(manifest: CapabilityManifest, ttl: Duration, secret: &[u8]) -> Self {
    let issued_at = Utc::now();
    let expires_at = issued_at + ttl;
    let signature = compute_mac(&manifest, &issued_at, &expires_at, secret).to_hex().to_string();

    Self {
        manifest,
        issued_at,
        expires_at,
        signature,
    }
}

pub fn verify(&self, secret: &[u8]) -> bool {
    // Check expiry first.
    if Utc::now() > self.expires_at {
        return false;
    }

    let expected = compute_mac(&self.manifest, &self.issued_at, &self.expires_at, secret);
    blake3::Hash::from_hex(&self.signature)
        .map(|h| h == expected)
        .unwrap_or(false)
}

pub fn is_expired(&self) -> bool {
    Utc::now() > self.expires_at
}

fn compute_mac(
    manifest: &CapabilityManifest,
    issued_at: &DateTime<Utc>,
    expires_at: &DateTime<Utc>,
    secret: &[u8],
) -> blake3::Hash {
    let key = blake3::derive_key("pincherOS/capability-token/v1", secret);
    let keyed = blake3::Hasher::new_keyed(&key);

    // We hash the serialised manifest + timestamps in a deterministic way.
    let manifest_json = serde_json::to_string(manifest).unwrap_or_default();
    let issued_str = issued_at.to_rfc3339();
    let expires_str = expires_at.to_rfc3339();

    let mut hasher = keyed;
    hasher.update(manifest_json.as_bytes());
    hasher.update(issued_str.as_bytes());
    hasher.update(expires_str.as_bytes());
    hasher.finalize()
}

fn mint_and_verify_round_trip() {
    let manifest = CapabilityManifest::empty(Uuid::new_v4());
    let secret = b"test-secret-key-1234567890123456";
    let token = CapabilityToken::mint(manifest, Duration::hours(1), secret);
    assert!(token.verify(secret));
}

fn wrong_secret_fails() {
    let manifest = CapabilityManifest::empty(Uuid::new_v4());
    let secret_a = b"secret-a-12345678901234567890";
    let secret_b = b"secret-b-12345678901234567890";
    let token = CapabilityToken::mint(manifest, Duration::hours(1), secret_a);
    assert!(!token.verify(secret_b));
}

pub fn covers_fs_write(&self, path: &str) -> bool {
    match self {
        Permission::FsWrite { path: pattern } => path_matches_pattern(pattern, path),
        _ => false,
    }
}

pub fn covers_fs_read(&self, path: &str) -> bool {
    match self {
        Permission::FsRead { path: pattern } => path_matches_pattern(pattern, path),
        // Write implies read.
        Permission::FsWrite { path: pattern } => path_matches_pattern(pattern, path),
        _ => false,
    }
}

pub fn covers_execute(&self, binary: &str) -> bool {
    match self {
        Permission::Execute { binary: allowed } => allowed == binary,
        _ => false,
    }
}

pub fn allows_network(&self) -> bool {
    matches!(self, Permission::NetConnect { .. })
}

