def __init__(self, llm: Optional[LLMInterface] = None, embedder: Optional[Embedder] = None):
    self.llm = llm or StubLLM()
    self.embedder = embedder or Embedder()

def _parse_response(self, response: str, user_input: str, action: str) -> Dict[str, Any]:
    """Parse the LLM response into a reflex definition.

    Falls back to heuristic distillation if parsing fails.
    """
    # Try to extract JSON from the response
    try:
        # Find JSON in the response (may be wrapped in markdown code blocks)
        json_match = re.search(r'\{[^{}]*\}', response, re.DOTALL)
        if json_match:
            parsed = json.loads(json_match.group())
            return {
                "trigger_pattern": parsed.get("trigger_pattern", user_input),
                "action_template": parsed.get("action_template", action),
                "guard_expr": parsed.get("guard_expr"),
                "post_condition": parsed.get("post_condition"),
                "composable": parsed.get("composable", False),
                "capability_hints": parsed.get("capability_hints", []),
            }
    except json.JSONDecodeError:
        pass

    # Heuristic fallback
    return self._heuristic_distill(user_input, action)

def _infer_capabilities(self, action: str) -> list:
    """Infer required capabilities from an action template."""
    capabilities = []

    if any(cmd in action for cmd in ["cat ", "ls ", "head ", "tail ", "grep ", "find "]):
        capabilities.append("FsRead")

    if any(cmd in action for cmd in ["mkdir ", "touch ", "rm ", "cp ", "mv ", "write "]):
        capabilities.append("FsWrite")

    if any(cmd in action for cmd in ["curl ", "wget ", "http ", "fetch "]):
        capabilities.append("NetHttp")

    if any(cmd in action for cmd in ["python", "bash", "sh ", "./", "node "]):
        capabilities.append("Execute")

    return capabilities if capabilities else ["FsRead"]

def _match_template(intent: str) -> Optional[DistillationResult]:
    """Try to match *intent* against the built-in template patterns.

    Returns a :class:`DistillationResult` on success, or ``None`` if no
    pattern matches.
    """
    for pattern, template in _TEMPLATE_PATTERNS:
        m = pattern.match(intent.strip())
        if m:
            params: dict[str, str] = {
                k: v for k, v in m.groupdict().items() if v is not None
            }
            return DistillationResult(
                action_template=template["action_template"],
                parameters=params,
                confidence_hint=float(template.get("confidence_hint", 0.5)),
                tags=list(template.get("tags", [])),
            )
    return None

def __init__(self, config: Optional[InferConfig] = None) -> None:
    self._config = config or InferConfig()
    self._client: Optional[OpenAI] = None
    if self._config.api_key:
        self._client = OpenAI(api_key=self._config.api_key)

def compile_intent(
    self,
    intent: str,
    context: Optional[dict[str, Any]] = None,
) -> DistillationResult:
    """Compile a natural-language *intent* into a :class:`DistillationResult`.

    Strategy:
      1. If an OpenAI key is configured, ask the LLM.
      2. Otherwise, fall back to built-in template matching.
      3. If neither produces a result, return a generic placeholder.
    """
    if self._client is not None:
        return self._compile_via_llm(intent, context or {})
    return self._compile_via_template(intent)

def _compile_via_llm(
    self,
    intent: str,
    context: dict[str, Any],
) -> DistillationResult:
    """Send *intent* to the LLM and parse the structured JSON response."""
    user_parts = [f"Intent: {intent}"]
    if context:
        user_parts.append(f"Context: {json.dumps(context)}")

    response = self._client.chat.completions.create(  # type: ignore[union-attr]
        model=self._config.model_name,
        messages=[
            {"role": "system", "content": DISTILL_SYSTEM_PROMPT},
            {"role": "user", "content": "\n".join(user_parts)},
        ],
        max_tokens=self._config.max_tokens,
        temperature=self._config.temperature,
    )
    content = response.choices[0].message.content
    if not content:
        return self._compile_via_template(intent)

    try:
        parsed = json.loads(content)
    except json.JSONDecodeError:
        # LLM sometimes wraps JSON in markdown fences — strip them.
        stripped = re.sub(r"^```(?:json)?\s*|\s*```$", "", content, flags=re.MULTILINE)
        try:
            parsed = json.loads(stripped)
        except json.JSONDecodeError:
            return self._compile_via_template(intent)

    return DistillationResult(
        action_template=parsed.get("action_template", ""),
        parameters=parsed.get("parameters", {}),
        confidence_hint=float(parsed.get("confidence_hint", 0.5)),
        tags=list(parsed.get("tags", [])),
    )

def _compile_via_template(intent: str) -> DistillationResult:
    """Match *intent* against built-in templates as a fallback."""
    result = _match_template(intent)
    if result is not None:
        return result
    # Ultimate fallback — wrap the intent as an echo so something runs.
    return DistillationResult(
        action_template='echo "Unrecognised intent: {{intent}}"',
        parameters={"intent": intent},
        confidence_hint=0.1,
        tags=["unknown"],
    )

def __init__(self, model: str = "llama3.2", host: str = "http://localhost:11434"):
    self.model = model
    self.host = host

def infer(self, prompt: str, context: str = "") -> str:
    """Run inference via Ollama API."""
    try:
        import ollama
        client = ollama.Client(host=self.host)
        full_prompt = f"{context}\n\n{prompt}" if context else prompt
        response = client.generate(model=self.model, prompt=full_prompt)
        return response.get("response", "")
    except ImportError:
        # Fallback to CLI
        return self._infer_cli(prompt, context)

def _infer_cli(self, prompt: str, context: str = "") -> str:
    """Run inference via ollama CLI."""
    full_prompt = f"{context}\n\n{prompt}" if context else prompt
    try:
        result = subprocess.run(
            ["ollama", "run", self.model, full_prompt],
            capture_output=True,
            text=True,
            timeout=120,
        )
        return result.stdout.strip()
    except (subprocess.TimeoutExpired, FileNotFoundError) as e:
        return f"[LLM error: {e}]"

def _ensure_loaded(self):
    """Lazy-load the model."""
    if self._llm is not None:
        return

    try:
        from llama_cpp import Llama
        self._llm = Llama(
            model_path=self.model_path,
            n_ctx=self.n_ctx,
            verbose=False,
        )
    except ImportError:
        raise RuntimeError("llama-cpp-python not installed")

def infer(self, prompt: str, context: str = "") -> str:
    """Run inference via llama.cpp."""
    self._ensure_loaded()

    full_prompt = f"{context}\n\n{prompt}" if context else prompt
    response = self._llm(
        full_prompt,
        max_tokens=512,
        temperature=0.7,
    )
    return response["choices"][0]["text"].strip()

def create_llm(backend: str = "ollama", **kwargs) -> Optional[LLMInterface]:
    """Factory function to create an LLM interface.

    Args:
        backend: "ollama", "llama.cpp", "stub", or "none"
        **kwargs: Additional arguments for the LLM backend

    Returns:
        An LLMInterface instance, or None if no LLM is available
    """
    if backend == "ollama":
        return OllamaInterface(**kwargs)
    elif backend == "llama.cpp":
        return LlamaCppInterface(**kwargs)
    elif backend == "stub":
        return StubLLM()
    else:
        return None

def embed(self, text: str) -> np.ndarray:
    """Embed a single text string.

    Returns:
        numpy array of shape (384,) with float32 values
    """
    self._ensure_loaded()

    if self._model is not None:
        embedding = self._model.encode(text, normalize_embeddings=True)
        return embedding.astype(np.float32)

    # Fallback: deterministic pseudo-embedding based on text hash
    return self._pseudo_embed(text)

def embed_batch(self, texts: List[str]) -> np.ndarray:
    """Embed multiple text strings.

    Returns:
        numpy array of shape (N, 384) with float32 values
    """
    self._ensure_loaded()

    if self._model is not None:
        embeddings = self._model.encode(texts, normalize_embeddings=True)
        return embeddings.astype(np.float32)

    return np.array([self._pseudo_embed(t) for t in texts], dtype=np.float32)

def dimension(self) -> int:
    """Return the embedding dimension."""
    return self._dimension

def is_ready(self) -> bool:
    """Check if the embedder is ready (model loaded or pseudo-embed available)."""
    return True  # Pseudo-embed is always available

def _read_toml(path: Path) -> dict:
    """Read a TOML file, returning an empty dict on failure."""
    if tomllib is None:
        return {}
    if not path.is_file():
        return {}
    try:
        with open(path, "rb") as fh:
            return tomllib.load(fh)  # type: ignore[union-attr]
    except Exception:
        return {}

def _get_model() -> object:
    """Lazily load and cache the sentence-transformers model."""
    global _model  # noqa: PLW0603
    if _model is not None:
        return _model
    try:
        from sentence_transformers import SentenceTransformer  # type: ignore[import-untyped]

        _model = SentenceTransformer(_model_name)
        logger.info("Loaded sentence-transformers model: %s", _model_name)
        return _model
    except ImportError:
        logger.warning(
            "sentence-transformers not available — embeddings will be zero-vectors. "
            "Install with: pip install sentence-transformers"
        )
        return None
    except Exception as exc:
        logger.error("Failed to load sentence-transformers model: %s", exc)
        return None

def embed(self, text: str) -> list[float]:
    """Return a float-vector embedding for *text*.

    Strategy:
      1. Try sentence-transformers (local, fast).
      2. Fall back to pincher-core RPC.
      3. Ultimate fallback: zero-vector (better than crashing).
    """
    model = _get_model()
    if model is not None:
        vec: NDArray[np.float32] = model.encode(text, convert_to_numpy=True)  # type: ignore[union-attr]
        return vec.tolist()

    if self._rpc_call is not None:
        try:
            result = self._rpc_call("embed", [text])  # type: ignore[operator]
            if isinstance(result, list):
                return result
        except Exception as exc:
            logger.warning("RPC embed fallback failed: %s", exc)

    logger.warning("Returning zero-vector embedding — no backend available")
    return [0.0] * self._dimension

def batch_embed(self, texts: list[str]) -> list[list[float]]:
    """Embed a batch of texts.

    Uses the model's native batch encoding when available for better
    throughput; otherwise falls back to sequential :meth:`embed` calls.
    """
    model = _get_model()
    if model is not None:
        vecs: NDArray[np.float32] = model.encode(texts, convert_to_numpy=True)  # type: ignore[union-attr]
        return vecs.tolist()

    # No model — try RPC batch or sequential fallback.
    if self._rpc_call is not None:
        try:
            result = self._rpc_call("batch_embed", [texts])  # type: ignore[operator]
            if isinstance(result, list):
                return result
        except Exception as exc:
            logger.warning("RPC batch_embed fallback failed: %s", exc)

    return [self.embed(t) for t in texts]

def call(self, method: str, params: Optional[list[Any]] = None) -> Any:
    """Send a JSON-RPC request to pincher-core and return the result.

    Uses a fresh socket connection for each call (simple, no connection
    management needed for the low request volume expected).
    """
    payload = {
        "jsonrpc": "2.0",
        "method": method,
        "params": params or [],
        "id": 1,
    }
    data = json.dumps(payload).encode("utf-8")

    try:
        with socket.socket(socket.AF_UNIX, socket.SOCK_STREAM) as sock:
            sock.settimeout(5.0)
            sock.connect(self._socket_path)
            sock.sendall(data + b"\n")
            # Read response — simple newline-delimited JSON.
            buf = b""
            while True:
                chunk = sock.recv(4096)
                if not chunk:
                    break
                buf += chunk
                if b"\n" in buf:
                    break
        resp = json.loads(buf.strip())
        if "error" in resp:
            raise RuntimeError(f"Core RPC error: {resp['error']}")
        return resp.get("result")
    except FileNotFoundError:
        logger.warning(
            "Core socket not found at %s — core may not be running",
            self._socket_path,
        )
        return None
    except Exception as exc:
        logger.error("Core RPC call '%s' failed: %s", method, exc)
        return None

def explain(self, reflex_id: str) -> str:
    """Generate a human-readable explanation for a reflex."""
    logger.info("explain(%s)", reflex_id)
    core = self._ensure_core()
    if core is None:
        return ""

    reflex_data = core.call("get_reflex", [reflex_id])
    if not reflex_data or not isinstance(reflex_data, dict):
        logger.error("Could not fetch reflex %s from core", reflex_id)
        return ""

    action = reflex_data.get("action_template", "")
    if not action:
        return "No action associated with this reflex."

    return self._distiller.explain(action)

def embed(self, text: str) -> list[float]:
    """Compute an embedding vector for *text*."""
    logger.debug("embed(%s)", text[:60])
    return self._embed.embed(text)

def batch_embed(self, texts: list[str]) -> list[list[float]]:
    """Compute embedding vectors for a batch of texts."""
    logger.debug("batch_embed(%d texts)", len(texts))
    return self._embed.batch_embed(texts)

def cosine_similarity(self, a: list[float], b: list[float]) -> float:
    """Compute cosine similarity between two vectors."""
    return EmbedService.cosine_similarity(a, b)

def shutdown(self) -> None:
    """Gracefully shut down the RPC server."""
    if self._rpc_server is not None:
        logger.info("Shutting down PincherInferServer")
        self._rpc_server.shutdown()

def _ensure_core(self) -> Optional[CoreBridge]:
    """Lazily initialise the core bridge."""
    if self._core is None:
        self._core = CoreBridge(self._config.socket_path)
    return self._core

